def truncate_headline(text, limit):
    if len(text) <= limit:
        return text
    truncated = text[:limit]
    last_space = truncated.rfind(' ')
    if last_space != -1:
        return truncated[:last_space] + '…'
    if limit <= 1:
        return '…' if limit == 1 else ''
    return text[:limit - 1] + '…'

def truncate_headline(text, limit):
    if len(text) <= limit:
        return text
    if limit <= 0:
        return ""
    ellipsis = "…"
    if limit <= len(ellipsis):
        return ellipsis
    max_content = limit - len(ellipsis)
    candidate = text[:max_content]
    for i in range(len(candidate) - 1, -1, -1):
        if candidate[i].isspace():
            return candidate[:i].rstrip() + ellipsis
    return candidate + ellipsis

