from urllib.parse import urlparse, parse_qsl, urlencode

def _canonical_url(url: str) -> str:
    """Return a normalized URL string suitable for deduplication."""
    try:
        parsed = urlparse(url.strip())
        # Lowercase and strip common subdomains
        netloc = parsed.netloc.lower()
        for prefix in ("www.", "m.", "mobile."):
            if netloc.startswith(prefix):
                netloc = netloc[len(prefix):]

        # Normalize path
        path = parsed.path.lower().rstrip("/")

        # Drop known tracking parameters and sort the rest
        drop_params = {
            "utm_source", "utm_medium", "utm_campaign",
            "utm_term", "utm_content", "fbclid", "gclid",
            "ref", "referrer", "source",
        }
        query_pairs = [
            (k.lower(), v)
            for k, v in parse_qsl(parsed.query, keep_blank_values=False)
            if k.lower() not in drop_params
        ]
        query_pairs.sort()
        query = urlencode(query_pairs)

        # Rebuild without scheme or fragment
        canonical = netloc + path
        if query:
            canonical += "?" + query
        return canonical
    except Exception:
        # Fallback for malformed URLs
        return url.strip().lower()


def dedupe_articles(articles):
    seen = set()
    result = []
    for article in articles:
        url = article.get("url", "")
        key = _canonical_url(url)
        if key not in seen:
            seen.add(key)
            result.append(article)
    return result

