def slugify(title):
    text = title.lower()
    slug_chars = []
    in_separator = False
    for ch in text:
        if ch.isalnum():
            slug_chars.append(ch)
            in_separator = False
        elif slug_chars and not in_separator:
            slug_chars.append('-')
            in_separator = True
    return ''.join(slug_chars).strip('-')

