def extract_domain(url):
    if not url:
        return ''

    # Use tldextract for full Public Suffix List coverage if available.
    try:
        import tldextract
        extracted = tldextract.extract(url)
        if extracted.domain and extracted.suffix:
            return f"{extracted.domain}.{extracted.suffix}".lower()
    except Exception:
        pass

    parsed = urlparse(url)
    hostname = parsed.hostname

    # Handle bare domains (e.g., "example.com/path") that urlparse treats a
as a scheme.
    if hostname is None:
        if '://' not in url and not url.startswith('//'):
            parsed = urlparse('http://' + url)
            hostname = parsed.hostname
        elif url.startswith('//'):
            parsed = urlparse('http:' + url)
            hostname = parsed.hostname

    if not hostname:
        return ''

    hostname = hostname.lower().rstrip('.')

    parts = hostname.split('.')
    if len(parts) == 4 and all(part.isdigit() for part in parts):
        return hostname

    if len(parts) < 2:
        return hostname

    suffix = '.'.join(parts[-2:])
    if suffix in _KNOWN_SUFFIXES and len(parts) >= 3:
        return '.'.join(parts[-3:])

    return '.'.join(parts[-2:])

